using namespace std;

bool solve(std::vector<long long> nums1) {
    int n = nums1.size();

    // Strategy: We need to check two possibilities:
    // 1. Can we make all elements of nums2 ODD?
    // 2. Can we make all elements of nums2 EVEN?

    auto check_parity = [&](bool target_is_odd) -> bool {
        // target_is_odd = true means we aim for all odd numbers in nums2
        // target_is_odd = false means we aim for all even numbers in nums2

        // We need to determine, for each i, if there exists a choice such that
        // nums2[i] has the target parity.

        for (int i = 0; i < n; ++i) {
            long long val_i = nums1[i];
            bool can_be_target_parity = false;

            // Option 1: nums2[i] = nums1[i]
            if ((val_i % 2 != 0) == target_is_odd) {
                can_be_target_parity = true;
            }

            // Option 2: nums2[i] = nums1[i] - nums1[j], j != i, nums1[i] - nums1[j] >= 1
            // The parity of (a - b) is the parity of (a + b).
            // (val_i - val_j) has target parity if (val_i % 2 - val_j % 2) % 2 == target_parity_mod_2.
            // Or simpler: val_i - val_j has the same parity as (val_i % 2) XOR (val_j % 2) != target_parity_mod_2

            // Target parity mod 2: 1 if odd, 0 if even.
            int target_mod_2 = target_is_odd ? 1 : 0;

            for (int j = 0; j < n; ++j) {
                if (i == j) continue;
                long long val_j = nums1[j];

                if (val_i - val_j >= 1) {
                    // Parity of (val_i - val_j) is (val_i % 2) - (val_j % 2) (modulo 2)
                    // If target is odd (1): we need (val_i - val_j) % 2 == 1.
                    // This happens if val_i and val_j have different parities.
                    // If target is even (0): we need (val_i - val_j) % 2 == 0.
                    // This happens if val_i and val_j have the same parity.

                    int result_parity_mod_2;
                    if ((val_i % 2) != (val_j % 2)) {
                        result_parity_mod_2 = 1; // Odd
                    } else {
                        result_parity_mod_2 = 0; // Even
                    }

                    if (result_parity_mod_2 == target_mod_2) {
                        can_be_target_parity = true;
                        break;
                    }
                }
            }

            if (!can_be_target_parity) {
                return false; // Cannot satisfy the target parity for index i
            }
        }
        return true; // All indices can satisfy the target parity
    };

    // Check possibility 1: All odd
    if (check_parity(true)) {
        return true;
    }

    // Check possibility 2: All even
    if (check_parity(false)) {
        return true;
    }

    return false;
}
